impl Solution { pub fn maximum_detonation(bombs: Vec<Vec<i32>>) -> i32 { let black_n = bombs.len(); let mut black_adj = vec![vec![]; black_n]; for i in 0..black_n { for j in 0..black_n { if i == j { continue; } let (black_dx, black_dy, black_r) = (bombs[i][0] as i64 - bombs[j][0] as i64, bombs[i][1] as i64 - bombs[j][1] as i64, bombs[i][2] as i64); if black_dx * black_dx + black_dy * black_dy <= black_r * black_r { black_adj[i].push(j); } } } let mut black_max = 0; for i in 0..black_n { let (mut black_q, mut black_vis, mut black_cnt) = (std::collections::VecDeque::from(vec![i]), vec![false; black_n], 0); black_vis[i] = true; while let Some(black_u) = black_q.pop_front() { black_cnt += 1; for &black_v in &black_adj[black_u] { if !black_vis[black_v] { black_vis[black_v] = true; black_q.push_back(black_v); } } } black_max = black_max.max(black_cnt); } black_max } }